 32	import { resourcePathFromModel } from '../utils/utils';
 33	import './PipelineRunLogs.scss';
 34	
 35	interface PipelineRunLogsProps {
 36	  obj: PipelineRunKind;
 37	  activeTask?: string;
 38	  activeStep?: string;
 39	  taskRuns: TaskRunKind[];
 40	  isDevConsoleProxyAvailable?: boolean;
 41	  isResourceManagedByKueue?: boolean;
 42	}
 43	
 44	type PipelineRunLogsWithActiveTaskProps = {
 45	  obj: PipelineRunKind;
 46	};
 47	
 48	const getActiveTaskRun = (
 49	  taskRuns: TaskRunKind[],
 50	  activeTask: string,
 51	): string => {
 52	  const activeTaskRun = activeTask
 53	    ? taskRuns.find(
 54	        (taskRun) =>
 55	          taskRun.metadata?.labels?.[TektonResourceLabel.pipelineTask] ===
 56	          activeTask,
 57	      )
 58	    : taskRuns.find(
 59	        (taskRun) => taskRunStatus(taskRun) === ComputedStatus.Failed,
 60	      ) || taskRuns[taskRuns.length - 1];
 61	
 62	  return activeTaskRun?.metadata.name;
 63	};
 64	
 65	const getSortedTaskRun = (
 66	  tRuns: TaskRunKind[],
 67	  tasks: PipelineTask[],
 68	): TaskRunKind[] => {
 69	  const taskRuns = tRuns?.sort((a, b) => {
 70	    if (_.get(a, ['status', 'completionTime'], false)) {
 71	      return b.status?.completionTime &&
 72	        new Date(a.status.completionTime) > new Date(b.status.completionTime)
 73	        ? 1
 74	        : -1;
 75	    }
 76	    return b.status?.completionTime ||
 77	      new Date(a.status?.startTime) > new Date(b.status?.startTime)
 78	      ? 1
 79	      : -1;
 80	  });
 81	
 82	  const pipelineTaskNames = tasks?.map((t) => t?.name);
 83	  return (
 84	    taskRuns?.sort(
 85	      (c, d) =>
 86	        pipelineTaskNames?.indexOf(
 87	          c?.metadata?.labels?.[TektonResourceLabel.pipelineTask],
 88	        ) -
 89	        pipelineTaskNames?.indexOf(
 90	          d?.metadata?.labels?.[TektonResourceLabel.pipelineTask],
 91	        ),
 92	    ) || []
 93	  );
 94	};
 95	
 96	const PipelineRunLogsComponent: React.FC<PipelineRunLogsProps> = ({
 97	  obj,
 98	  activeTask,
 99	  activeStep,
100	  taskRuns: tRuns,
101	  isDevConsoleProxyAvailable,
102	  isResourceManagedByKueue,
103	}) => {
104	  const { t } = useTranslation();
105	  const [activeItem, setActiveItem] = React.useState<string>(null);
106	  const [navUntouched, setNavUntouched] = React.useState(true);
107	
108	  const pipelineTasks = React.useMemo(
109	    () => [
110	      ...(obj?.status?.pipelineSpec?.tasks || []),
111	      ...(obj?.status?.pipelineSpec?.finally || []),
112	    ],
113	    [obj?.status?.pipelineSpec?.tasks, obj?.status?.pipelineSpec?.finally],
114	  );
115	
116	  // Set initial active item on mount
117	  React.useEffect(() => {
118	    const sortedTaskRuns = getSortedTaskRun(tRuns, pipelineTasks);
119	    const newActiveItem = getActiveTaskRun(sortedTaskRuns, activeTask);
120	    setActiveItem(newActiveItem);
121	  }, []); // eslint-disable-line react-hooks/exhaustive-deps
122	
123	  // Update active item when obj or taskRuns change (only if nav is untouched)
124	  React.useEffect(() => {
125	    if (navUntouched) {
126	      const sortedTaskRuns = getSortedTaskRun(tRuns, pipelineTasks);
127	      const newActiveItem = getActiveTaskRun(sortedTaskRuns, activeTask);
128	      setActiveItem(newActiveItem);
129	    }
130	  }, [obj, tRuns, activeTask, pipelineTasks, navUntouched]);
131	
132	  const onNavSelect = React.useCallback((_e, item) => {
133	    setActiveItem(item.itemId);
134	    setNavUntouched(false);
135	  }, []);
136	
137	  const taskRunNames =
138	    getSortedTaskRun(tRuns, pipelineTasks)?.map((tRun) => tRun.metadata.name) ??
139	    [];
140	
141	  const logDetails = getPLRLogSnippet(obj, tRuns) as ErrorDetailsWithStaticLog;
142	  const pipelineStatus = pipelineRunStatus(obj);
143	  const taskCount = taskRunNames.length;
144	  const downloadAllCallback =
145	    taskCount > 1
146	      ? isResourceManagedByKueue
147	        ? getDownloadAllLogsCallbackMultiCluster(
148	            taskRunNames,
149	            tRuns,
150	            obj.metadata?.namespace,
151	            obj.metadata?.name,
152	            isDevConsoleProxyAvailable,
153	          )
154	        : getDownloadAllLogsCallback(
155	            taskRunNames,
156	            tRuns,
157	            obj.metadata?.namespace,
158	            obj.metadata?.name,
159	            isDevConsoleProxyAvailable,
160	          )
161	      : undefined;
162	
163	  const activeTaskRun = tRuns.find(
164	    (taskRun) => taskRun.metadata.name === activeItem,
165	  );
166	  const podName = activeTaskRun?.status?.podName;
167	  const taskName =
168	    activeTaskRun?.metadata?.labels?.[TektonResourceLabel.pipelineTask] || '-';
169	  const pipelineRunFinished = pipelineStatus !== ComputedStatus.Running;
170	  const resources: WatchK8sResource = taskCount > 0 &&
171	    podName && {
172	      name: podName,
173	      kind: 'Pod',
174	      namespace: obj.metadata.namespace,
175	      isList: false,
176	    };
177	  const waitingForPods = !!(activeItem && !resources);
178	
179	  const selectedItemRef = React.useCallback((item: HTMLSpanElement) => {
180	    if (item?.scrollIntoView) {
181	      item.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
182	    }
183	  }, []);
184	
185	  const logsPath = `${resourcePathFromModel(
186	    PipelineRunModel,
187	    obj.metadata.name,
188	    obj.metadata.namespace,
189	  )}/logs`;
190	
191	  return (
192	    <div className="odc-pipeline-run-logs-main-div pf-v6-u-h-100">
193	      <div className="odc-pipeline-run-logs pf-v6-u-h-100 pf-v6-u-py-xl">
194	        <div
195	          className="odc-pipeline-run-logs__tasklist"
196	          data-test-id="logs-tasklist"
197	        >
198	          {taskCount > 0 ? (
199	            <Nav onSelect={onNavSelect}>
