203	                    (tRun) => tRun.metadata.name === taskRunName,
204	                  );
205	                  return (
206	                    <NavItem
207	                      key={taskRunName}
208	                      itemId={taskRunName}
209	                      isActive={activeItem === taskRunName}
210	                      className="odc-pipeline-run-logs__navitem"
211	                    >
212	                      <Link
213	                        to={`${logsPath}?taskName=${
