305	    plrStatus !== ComputedStatus.Running &&
306	    plrStatus !== ComputedStatus.Pending &&
307	    plrStatus !== ComputedStatus.Cancelling;
308	  const [taskRuns, taskRunsLoaded, , , pendingAdmission, proxyUnavailable] =
309	    useTaskRuns(obj?.metadata?.namespace, obj?.metadata?.name, {
310	      pipelineRunFinished,
311	      pipelineRunManagedBy: obj?.spec?.managedBy
312	    });
313	  const { isResourceManagedByKueue } = useMultiClusterProxyService({ managedBy: obj?.spec?.managedBy });
314	
315	  return (
316	    <>
317	      {proxyUnavailable && (
318	        <Alert
319	          isInline
320	          variant="warning"
321	          title={t(
322	            'The multi-cluster connection is unavailable. Logs and status may be delayed until connection is restored.',
323	          )}
324	        />
325	      )}
326	      {pendingAdmission && (
327	        <Alert
328	          isInline
329	          variant="info"
330	          title={t('PipelineRun is waiting to be admitted to a worker cluster')}
331	        />
332	      )}
333	      {taskRunsLoaded && (
334	        <PipelineRunLogs
335	          obj={obj}
336	          activeTask={activeTask}
337	          activeStep={activeStep}
338	          taskRuns={taskRuns}
339	          isResourceManagedByKueue={isResourceManagedByKueue}
340	        />
341	      )}
342	    </>
343	  );
344	};
